export default meta;
type Story = StoryObj<typeof HxUpload>;

/**
 * Default upload component with button trigger and list view
 */
export const Default: Story = {
	args: {
		$model: ERO.reactive({files: []}),
		$field: 'files'
	}
};

// eslint-disable-next-line @typescript-eslint/no-unused-vars
const upload = async <T extends object>(files: Array<File>, _$model: HxObject<T>, _context: HxContext): Promise<Array<HxUploadingFile>> => {
	return Promise.all(files.map(async file => {
		const bytes = await file.bytes();
		const f = {
			name: file.name,
			size: file.size,
			mimeType: file.type,
			bytes
		};
		const abort = new AbortController();
		return {
			details: f,
			percentageSupport: true,
			upload: async (callback: HxUploadFileCallbackFunc): Promise<HxUploadFile | HxUploadErrorMessage> => {
				return new Promise((resolve, reject) => {
					let percentage = 0;
					const part = (mockError: boolean) => {
						if (abort.signal.aborted) {
							reject();
						} else {
							setTimeout(() => {
								percentage = Math.min(100, percentage + 5 + Math.random() * 10);
								callback(percentage);
								if (percentage < 100) {
									if (mockError) {
										const random = Math.random();
										console.log(mockError, random);
										if (random >= 0.4) {
											part(false);
										} else if (random < 0.1) {
											resolve('error');
										} else if (random < 0.2) {
											resolve('over-max-size');
										} else if (random < 0.3) {
											resolve('not-acceptable');
										} else {
											resolve('Upload error.');
										}
									} else {
										part(false);
									}
								} else {
									const {name, size, mimeType} = f;
									resolve({name, size, mimeType});
								}
							}, 100);
						}
					};
					part(true);
				});
			},
			abort
		};
	}));
};

